import axios from 'axios';
import { useEffect, useState } from 'react';
import { useParams } from 'react-router-dom';
import { useLanguage } from '../../context/language';
import { LoadingPage } from '../loading-page';
import { formatLanguageToApi } from '../utils/api-utils';
import Youtube, { YouTubeEvent, YouTubeProps } from 'react-youtube';
import { useTheme } from '../../context/theme';

interface videoResultsType {
	iso_639_1: string;
	iso_3166_1: string;
	name: string;
	key: string;
	site: string;
	size: number;
	type: string;
	official: boolean;
	published_at: string;
	id: string;
}

interface MovieBio {
	title: string;
	poster: string;
	banner: string;
	synopsis: string;
	rating: number;
	videosData?: Array<videoResultsType>;
}

export function MovieBiography() {
	const [isLoading, setIsLoading] = useState(false);
	const [movieBioState, setMovieBioState] = useState<MovieBio>({
		title: '',
		poster: '',
		banner: '',
		synopsis: '',
		rating: 0
	});

	const { movieId } = useParams();
	const { language } = useLanguage();
	const { theme } = useTheme();

	const token = `Bearer ${process.env.REACT_APP_TMDB_BEARER_TOKEN}`;
	const movieDataUrl = `https://api.themoviedb.org/3/movie/${movieId}?api_key=${process.env.REACT_APP_TMDB_API_KEY}&language=${formatLanguageToApi(language)}`;
	const movieVideosUrl = `https://api.themoviedb.org/3/movie/${movieId}/videos?api_key=${process.env.REACT_APP_TMDB_API_KEY}&language=${formatLanguageToApi(language)}`;

	async function getMovieData() {
		setIsLoading(true);
		const response = await axios({
			method: 'get',
			url: movieDataUrl,
			headers: { Authorization: token }
		});

		setMovieBioState({
			...movieBioState,
			title: response.data.title,
			poster: response.data.poster_path,
			banner: response.data.backdrop_path,
			synopsis: response.data.overview,
			rating: response.data.vote_average
		});
		setIsLoading(false);
	}

	async function getMovieTrailer() {
		const response = await axios({
			method: 'get',
			url: movieVideosUrl,
			headers: { Authorization: token }
		});

		setMovieBioState({
			...movieBioState,
			videosData: response.data.results
		});
	}

	useEffect(() => {
		getMovieData();
	}, [language]);

	useEffect(() => {
		if (movieBioState.title) {
			getMovieTrailer();
		}
	}, [movieBioState.title]);

	// : YouTubeProps['opts']
	const [opts, setOpts] = useState({
		height: '390',
		width: '640',
		playerVars: {
			// https://developers.google.com/youtube/player_parameters
			autoplay: 1
		},
		volume: '20'
	});

	return (
		<div className={`${theme.themeTextClassName} ${theme.lighterThemeBgClassName} min-h-screen`}>
			{isLoading ? (
				<LoadingPage />
			) : (
				<>
					<div className='bg-white'>
						<img className='w-full max-h-p110x blur-sm brightness-50' src={`https://image.tmdb.org/t/p/w1280${movieBioState?.banner}`}/>
					</div>
					<div className="flex items-center justify-center text-center font-semibold p-3 self-auto align-middle">
						<img className="rounded-lg h-100 w-80" src={`https://image.tmdb.org/t/p/w500${movieBioState?.poster}`} alt="Movie Poster Url"></img>
						<p className="p-8">{movieBioState?.title}</p>
						{movieBioState.videosData ? (
							// <iframe
							// 	width="560"
							// 	height="315"
							// 	src={`https://www.youtube.com/embed/${movieBioState.videosData[0].key}?autoplay=1&volume=25`}
							// 	title="YouTube video player"
							// 	allow="accelerometer; autoplay; clipboard-write; encrypted-media; gyroscope; picture-in-picture; web-share"
							// 	allowFullScreen
							// ></iframe>
							<Youtube videoId={movieBioState.videosData[0].key} opts={opts} />
						) : (
							<span>Loading video...</span>
						)}

						<p>{movieBioState?.synopsis}</p>
						<p>{movieBioState?.rating}</p>
					</div>
				</>
			)}
		</div>
	);
}
